class Solution {
    public int countKReducibleNumbers(String s, int k) {
        int n = s.length();
        long[] dp = new long[n + 1];
        long[] dp2 = new long[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            dp[i] = (dp[i - 1] + dp2[i - 1]) % 1000000007;
            int count = 0;
            for (int j = i - 1; j >= 0; j--) {
                if (s.charAt(j) == '1') {
                    count++;
                }
                if (j == 0 || s.charAt(j - 1) == '0') {
                    dp2[i] = (dp2[i] + dp[j]) % 1000000007;
                }
            }
        }
        long ans = 0;
        for (int i = 0; i <= n; i++) {
            if (k >= i) {
                ans = (ans + dp[i]) % 1000000007;
            }
        }
        return (int) ans;
    }
}
